173→        var wordCount = dataByteCount / 2;
174→        var words = new ushort[wordCount];
175→        for (int i = 0; i < wordCount; i++)
176→        {
177→            if (offset + 2 > length) break;
178→            words[i] = BitConverter.ToUInt16(response, offset);
179→            offset += 2;
