188→        if (offset + 2 > length)
189→            return new(false, CMD_WSS_RSP, DATA_TYPE_WORD, null,
190→                $"쓰기 응답 데이터 부족 ({length}B)");
191→
192→        var blockCount = BitConverter.ToUInt16(response, offset);
193→        return new(blockCount > 0, CMD_WSS_RSP, DATA_TYPE_WORD, null,
