233→        writer.Write((byte)0x00);               // [21] BCC (미사용)
234→
235→        // --- 애플리케이션 명령 ---
236→        writer.Write(command);                  // [22-23] Command
237→        writer.Write(DATA_TYPE_WORD);           // [24-25] Data Type
