 93→    /// <summary>
 94→    /// 응답 패킷 파싱 결과
 95→    /// </summary>
 96→    public record ParseResult(
 97→        bool Success,
 98→        ushort Command,
 99→        ushort DataType,
100→        ushort[]? Words,
101→        string ErrorInfo);
102→
103→    /// <summary>
104→    /// 응답 패킷 파싱 (범용 — 읽기/쓰기 모두)
105→    /// </summary>
106→    public static ParseResult ParseResponse(byte[] response, int length)
107→    {
108→        // 최소 헤더(20) + cmd(2) + dtype(2) = 24바이트
109→        if (length < 24)
110→            return new(false, 0, 0, null,
111→                $"응답 너무 짧음: {length}B (최소 24B 필요)");
112→
113→        // 헤더 파싱 (20바이트 기준)
114→        var source = response[13];
115→        var dataLen = BitConverter.ToUInt16(response, 16);
116→        var command = BitConverter.ToUInt16(response, 20);
117→        var dataType = BitConverter.ToUInt16(response, 22);
118→
119→        // 방향 확인
120→        if (source != SOURCE_RESPONSE)
121→            return new(false, command, dataType, null,
122→                $"응답 Source=0x{source:X2} (0x11 예상)");
123→
124→        // cmd(2) + dtype(2) 이후 = 바이트 24부터
125→        var appDataOffset = 24;
126→        var appDataLen = length - appDataOffset;
127→
128→        if (appDataLen < 2)
129→            return new(false, command, dataType, null,
130→                $"데이터 없음: cmd=0x{command:X4}, dataLen={dataLen}, total={length}B");
131→
132→        // 읽기 응답 (0x0055)
133→        if (command == CMD_RSS_RSP)
134→            return ParseReadData(response, length, appDataOffset);
135→
136→        // 쓰기 응답 (0x0059)
137→        if (command == CMD_WSS_RSP)
138→            return ParseWriteData(response, length, appDataOffset);
139→
140→        // 알 수 없는 명령
141→        return new(false, command, dataType, null,
142→            $"미지원 응답 cmd=0x{command:X4}");
143→    }
144→
145→    private static ParseResult ParseReadData(byte[] response, int length, int offset)
146→    {
147→        // [offset+0,1] = 블록 수
148→        var blockCount = BitConverter.ToUInt16(response, offset);
149→        offset += 2;
150→
151→        if (offset + 2 > length)
152→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
153→                $"블록 수={blockCount}, 데이터 부족 ({length}B)");
154→
155→        // [offset+0,1] = 데이터 바이트 수
156→        var dataByteCount = BitConverter.ToUInt16(response, offset);
157→        offset += 2;
158→
159→        // 에러 체크: dataByteCount가 0xFFFF이면 에러 코드
160→        if (dataByteCount == 0xFFFF)
161→        {
162→            // 에러 응답: 다음 2바이트가 에러 정보
163→            ushort errInfo = (offset + 2 <= length)
164→                ? BitConverter.ToUInt16(response, offset) : (ushort)0;
165→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
166→                $"PLC 에러: code=0x{dataByteCount:X4}, info=0x{errInfo:X4} (주소 미존재 또는 M영역 미할당)");
167→        }
168→
169→        // 에러 체크: dataByteCount가 0이거나 비정상이면
170→        if (dataByteCount == 0 || offset + dataByteCount > length)
171→        {
172→            var remaining = length - offset + 2;
173→            var dump = BitConverter.ToString(response, offset - 2,
174→                Math.Min(remaining + 2, length - offset + 2));
175→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
176→                $"블록={blockCount}, 데이터크기={dataByteCount}, 잔여={dump}");
177→        }
178→
179→        // WORD 배열 추출
180→        var wordCount = dataByteCount / 2;
181→        var words = new ushort[wordCount];
182→        for (int i = 0; i < wordCount; i++)
183→        {
184→            if (offset + 2 > length) break;
185→            words[i] = BitConverter.ToUInt16(response, offset);
186→            offset += 2;
187→        }
188→
189→        return new(true, CMD_RSS_RSP, DATA_TYPE_WORD, words, "OK");
190→    }
191→
192→    private static ParseResult ParseWriteData(byte[] response, int length, int offset)
193→    {
194→        // 쓰기 응답: 블록 수만 확인
195→        if (offset + 2 > length)
196→            return new(false, CMD_WSS_RSP, DATA_TYPE_WORD, null,
197→                $"쓰기 응답 데이터 부족 ({length}B)");
198→
199→        var blockCount = BitConverter.ToUInt16(response, offset);
200→        return new(blockCount > 0, CMD_WSS_RSP, DATA_TYPE_WORD, null,
201→            blockCount > 0 ? "쓰기 OK" : "쓰기 실패 (block=0)");
202→    }
203→
204→    /// <summary>
205→    /// 응답 헤더를 사람이 읽을 수 있게 덤프
206→    /// </summary>
207→    public static string DumpResponseHeader(byte[] response, int length)
208→    {
209→        if (length < 20) return $"[헤더 부족: {length}B]";
210→
211→        var sb = new StringBuilder();
212→        var companyId = Encoding.ASCII.GetString(response, 0, 8).TrimEnd('\0');
213→        sb.Append($"ID={companyId}");
214→        sb.Append($" src=0x{response[13]:X2}");
215→        sb.Append($" len={BitConverter.ToUInt16(response, 16)}");
216→        if (length >= 22) sb.Append($" cmd=0x{BitConverter.ToUInt16(response, 20):X4}");
217→        if (length >= 24) sb.Append($" type=0x{BitConverter.ToUInt16(response, 22):X4}");
218→        return sb.ToString();
219→    }
220→
221→    private static byte[] BuildPacket(ushort command, int dataFrameLen,
222→        Action<BinaryWriter> writeDataFrame)
223→    {
224→        using var ms = new MemoryStream();
225→        using var writer = new BinaryWriter(ms);
226→
227→        // --- 헤더 (20바이트) ---
228→        writer.Write(COMPANY_ID);               // [0-9] "LSIS-XGT\0\0"
229→        writer.Write((ushort)0x0000);           // [10-11] PLC Info
230→        writer.Write(CPU_INFO);                 // [12] CPU Info
231→        writer.Write(SOURCE_REQUEST);           // [13] Source = 요청
232→        writer.Write((ushort)0x0000);           // [14-15] Invoke ID
233→
234→        // [16-17] Length = cmd(2) + dtype(2) + dataFrame
235→        var appLen = (ushort)(APP_CMD_SIZE + dataFrameLen);
236→        writer.Write(appLen);
237→
238→        writer.Write((byte)0x00);               // [18] Slot/Position
239→        writer.Write((byte)0x00);               // [19] BCC (미사용)
240→
241→        // --- 애플리케이션 명령 ---
242→        writer.Write(command);                  // [20-21] Command
243→        writer.Write(DATA_TYPE_WORD);           // [22-23] Data Type
244→
245→        // --- 데이터 프레임 ---
246→        writeDataFrame(writer);
247→
248→        return ms.ToArray();
249→    }
250→}
