using System;
using System.IO;
using System.Text;
using System.Text.RegularExpressions;

namespace AssembleMonitor.Features.Communication;

/// <summary>
/// LS XGT FEnet 프로토콜 패킷 생성/파싱
/// XGT 전용 프로토콜 (포트 2004)
///
/// 헤더 구조 (20바이트):
/// [0-9]   CompanyID: "LSIS-XGT\0\0"
/// [10-11] PLC Info
/// [12]    CPU Info (0xA0 = XGI/XGR/XEC)
/// [13]    Source of Frame (0x33=요청, 0x11=응답)
/// [14-15] Invoke ID
/// [16-17] Data Length (바이트 20 이후 길이)
/// [18]    Slot/Position
/// [19]    BCC
///
/// 애플리케이션 데이터 (20바이트~):
/// [20-21] Command (0x0054=RSS, 0x0058=WSS)
/// [22-23] Data Type (0x0014=WORD)
/// [24-25] Reserved (0x0000) ← 필수!
/// [26+]   데이터 프레임
///
/// 주소 변환 규칙 (XGT FEnet):
/// - Word 읽기/쓰기 시 주소를 Byte 기반으로 변환
/// - %MW100 → %MB200 (index×2), count도 BYTE 단위
/// - %IW0.0.0 → %IB0.0.0, %QW → %QB 등
/// </summary>
public static class XgtProtocol
{
    // CompanyID (10바이트)
    private static readonly byte[] COMPANY_ID =
        [0x4C, 0x53, 0x49, 0x53, 0x2D, 0x58, 0x47, 0x54, 0x00, 0x00]; // "LSIS-XGT\0\0"

    private const byte CPU_INFO = 0xA0;        // XGI/XGR/XEC
    private const byte SOURCE_REQUEST = 0x33;   // PC → PLC
    private const byte SOURCE_RESPONSE = 0x11;  // PLC → PC

    // 명령어
    private const ushort CMD_RSS_REQ = 0x0054;  // 연속 읽기 요청
    private const ushort CMD_RSS_RSP = 0x0055;  // 연속 읽기 응답
    private const ushort CMD_WSS_REQ = 0x0058;  // 연속 쓰기 요청
    private const ushort CMD_WSS_RSP = 0x0059;  // 연속 쓰기 응답

    // 데이터 타입
    private const ushort DATA_TYPE_WORD = 0x0014;

    // %MW100 → %MB200 변환 정규식 (M/D/L/K/F 영역)
    private static readonly Regex RxWordAddr =
        new(@"^%([MDLKF])W(\d+)$", RegexOptions.Compiled | RegexOptions.IgnoreCase);

    // %IW0.0.0 → %IB0.0.0 / %QW0.0.0 → %QB0.0.0 변환
    private static readonly Regex RxIoWordAddr =
        new(@"^%([IQU])W(.+)$", RegexOptions.Compiled | RegexOptions.IgnoreCase);

    /// <summary>
    /// Word 주소를 Byte 주소로 변환 (XGT FEnet 규칙)
    /// %MW100 → %MB200, %IW0.0.0 → %IB0.0.0, %UW0.9.1 → %UB0.9.1
    /// </summary>
    private static string ConvertToByteAddress(string wordAddress)
    {
        // M/D/L/K/F 영역: %MW100 → %MB200 (index×2)
        var m = RxWordAddr.Match(wordAddress);
        if (m.Success)
        {
            var device = m.Groups[1].Value.ToUpper();
            var index = int.Parse(m.Groups[2].Value);
            return $"%{device}B{index * 2}";
        }

        // I/Q/U 영역: %IW0.0.0 → %IB0.0.0 (dot 형식은 index 변환 불요)
        var m2 = RxIoWordAddr.Match(wordAddress);
        if (m2.Success)
        {
            var device = m2.Groups[1].Value.ToUpper();
            var rest = m2.Groups[2].Value;
            return $"%{device}B{rest}";
        }

        // 변환 불가 — 원본 그대로 반환
        return wordAddress;
    }

    /// <summary>
    /// 연속 WORD 읽기 요청 패킷 (RSS)
    /// startAddress: %MW100 형태 → 내부에서 %MB200으로 변환
    /// </summary>
    public static byte[] BuildReadRequest(string startAddress, ushort wordCount)
    {
        var byteAddr = ConvertToByteAddress(startAddress);
        var addrBytes = Encoding.ASCII.GetBytes(byteAddr);
        var addrLen = (ushort)addrBytes.Length;
        var byteCount = (ushort)(wordCount * 2);

        // 데이터 프레임: Reserved(2) + 블록수(2) + 주소길이(2) + 주소(N) + 읽기BYTE수(2)
        var dataFrameLen = 2 + 2 + 2 + addrLen + 2;

        return BuildPacket(CMD_RSS_REQ, dataFrameLen, writer =>
        {
            writer.Write((ushort)0x0000);   // Reserved (필수!)
            writer.Write((ushort)1);        // 블록 수
            writer.Write(addrLen);          // 주소 문자열 길이
            writer.Write(addrBytes);        // 주소 문자열 (BYTE 기반)
            writer.Write(byteCount);        // 읽을 BYTE 수
        });
    }

    /// <summary>
    /// 연속 WORD 쓰기 요청 패킷 (WSS)
    /// startAddress: %MW200 형태 → 내부에서 %MB400으로 변환
    /// </summary>
    public static byte[] BuildWriteRequest(string startAddress, ushort[] values)
    {
        var byteAddr = ConvertToByteAddress(startAddress);
        var addrBytes = Encoding.ASCII.GetBytes(byteAddr);
        var addrLen = (ushort)addrBytes.Length;
        var wordCount = (ushort)values.Length;
        var byteCount = (ushort)(wordCount * 2);

        // 데이터 프레임: Reserved(2) + 블록수(2) + 주소길이(2) + 주소(N) + BYTE수(2) + 데이터(N*2)
        var dataFrameLen = 2 + 2 + 2 + addrLen + 2 + byteCount;

        return BuildPacket(CMD_WSS_REQ, dataFrameLen, writer =>
        {
            writer.Write((ushort)0x0000);   // Reserved (필수!)
            writer.Write((ushort)1);        // 블록 수
            writer.Write(addrLen);          // 주소 문자열 길이
            writer.Write(addrBytes);        // 주소 문자열 (BYTE 기반)
            writer.Write(byteCount);        // BYTE 수
            foreach (var val in values)
                writer.Write(val);
        });
    }

    /// <summary>
    /// 응답 패킷 파싱 결과
    /// </summary>
    public record ParseResult(
        bool Success,
        ushort Command,
        ushort DataType,
        ushort[]? Words,
        string ErrorInfo);

    /// <summary>
    /// 응답 패킷 파싱 (범용 — 읽기/쓰기 모두)
    /// 응답에도 Reserved(2) 포함: cmd(2)+dtype(2)+reserved(2)+data
    /// </summary>
    public static ParseResult ParseResponse(byte[] response, int length)
    {
        // 최소 헤더(20) + cmd(2) + dtype(2) + reserved(2) = 26바이트
        if (length < 26)
            return new(false, 0, 0, null,
                $"응답 너무 짧음: {length}B (최소 26B 필요)");

        // 헤더 파싱 (20바이트 기준)
        var source = response[13];
        var dataLen = BitConverter.ToUInt16(response, 16);
        var command = BitConverter.ToUInt16(response, 20);
        var dataType = BitConverter.ToUInt16(response, 22);
        // [24-25] = Reserved (스킵)

        // 방향 확인
        if (source != SOURCE_RESPONSE)
            return new(false, command, dataType, null,
                $"응답 Source=0x{source:X2} (0x11 예상)");

        // cmd(2) + dtype(2) + reserved(2) 이후 = 바이트 26부터
        // 단, 응답에 Reserved가 없을 수도 있으므로 24부터 시도
        var appDataOffset = 24;
        var appDataLen = length - appDataOffset;

        if (appDataLen < 2)
            return new(false, command, dataType, null,
                $"데이터 없음: cmd=0x{command:X4}, dataLen={dataLen}, total={length}B");

        // 읽기 응답 (0x0055)
        if (command == CMD_RSS_RSP)
            return ParseReadData(response, length, appDataOffset);

        // 쓰기 응답 (0x0059)
        if (command == CMD_WSS_RSP)
            return ParseWriteData(response, length, appDataOffset);

        // 알 수 없는 명령
        return new(false, command, dataType, null,
            $"미지원 응답 cmd=0x{command:X4}");
    }

    private static ParseResult ParseReadData(byte[] response, int length, int offset)
    {
        // [offset+0,1] = 블록 수
        var blockCount = BitConverter.ToUInt16(response, offset);
        offset += 2;

        if (offset + 2 > length)
            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
                $"블록 수={blockCount}, 데이터 부족 ({length}B)");

        // [offset+0,1] = 데이터 바이트 수
        var dataByteCount = BitConverter.ToUInt16(response, offset);
        offset += 2;

        // 에러 체크: dataByteCount가 0xFFFF이면 에러 코드
        if (dataByteCount == 0xFFFF)
        {
            ushort errInfo = (offset + 2 <= length)
                ? BitConverter.ToUInt16(response, offset) : (ushort)0;
            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
                $"PLC 에러: code=0xFFFF, info=0x{errInfo:X4}");
        }

        // 에러 체크: dataByteCount가 0이거나 비정상이면
        if (dataByteCount == 0 || offset + dataByteCount > length)
        {
            var remaining = length - offset + 2;
            var dump = BitConverter.ToString(response, offset - 2,
                Math.Min(remaining + 2, length - offset + 2));
            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
                $"블록={blockCount}, 데이터크기={dataByteCount}, 잔여={dump}");
        }

        // WORD 배열 추출
        var wordCount = dataByteCount / 2;
        var words = new ushort[wordCount];
        for (int i = 0; i < wordCount; i++)
        {
            if (offset + 2 > length) break;
            words[i] = BitConverter.ToUInt16(response, offset);
            offset += 2;
        }

        return new(true, CMD_RSS_RSP, DATA_TYPE_WORD, words, "OK");
    }

    private static ParseResult ParseWriteData(byte[] response, int length, int offset)
    {
        if (offset + 2 > length)
            return new(false, CMD_WSS_RSP, DATA_TYPE_WORD, null,
                $"쓰기 응답 데이터 부족 ({length}B)");

        var blockCount = BitConverter.ToUInt16(response, offset);
        return new(blockCount > 0, CMD_WSS_RSP, DATA_TYPE_WORD, null,
            blockCount > 0 ? "쓰기 OK" : "쓰기 실패 (block=0)");
    }

    /// <summary>
    /// 응답 헤더를 사람이 읽을 수 있게 덤프
    /// </summary>
    public static string DumpResponseHeader(byte[] response, int length)
    {
        if (length < 20) return $"[헤더 부족: {length}B]";

        var sb = new StringBuilder();
        var companyId = Encoding.ASCII.GetString(response, 0, 8).TrimEnd('\0');
        sb.Append($"ID={companyId}");
        sb.Append($" src=0x{response[13]:X2}");
        sb.Append($" len={BitConverter.ToUInt16(response, 16)}");
        if (length >= 22) sb.Append($" cmd=0x{BitConverter.ToUInt16(response, 20):X4}");
        if (length >= 24) sb.Append($" type=0x{BitConverter.ToUInt16(response, 22):X4}");
        return sb.ToString();
    }

    private static byte[] BuildPacket(ushort command, int dataFrameLen,
        Action<BinaryWriter> writeDataFrame)
    {
        using var ms = new MemoryStream();
        using var writer = new BinaryWriter(ms);

        // --- 헤더 (20바이트) ---
        writer.Write(COMPANY_ID);               // [0-9] "LSIS-XGT\0\0"
        writer.Write((ushort)0x0000);           // [10-11] PLC Info
        writer.Write(CPU_INFO);                 // [12] CPU Info
        writer.Write(SOURCE_REQUEST);           // [13] Source = 요청
        writer.Write((ushort)0x0000);           // [14-15] Invoke ID

        // [16-17] Length = cmd(2) + dtype(2) + dataFrame (Reserved 포함)
        var appLen = (ushort)(4 + dataFrameLen);
        writer.Write(appLen);

        writer.Write((byte)0x00);               // [18] Slot/Position
        writer.Write((byte)0x00);               // [19] BCC

        // --- 애플리케이션 ---
        writer.Write(command);                  // [20-21] Command
        writer.Write(DATA_TYPE_WORD);           // [22-23] Data Type

        // --- 데이터 프레임 (Reserved + block + addr + count) ---
        writeDataFrame(writer);

        return ms.ToArray();
    }
}

