using System;
using System.Collections.ObjectModel;
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Windows;
using AssembleMonitor.Features.Communication;
using AssembleMonitor.Models;
using static AssembleMonitor.Features.IoMonitor.MemoryMapDefinition;

namespace AssembleMonitor.Features.IoMonitor;

/// <summary>
/// I/O 모니터 뷰모델 — PLC 비트 데이터 실시간 표시
/// </summary>
public class IoMonitorViewModel : INotifyPropertyChanged, IDisposable
{
    private readonly XgtClient _client = new();
    private CancellationTokenSource? _cts;

    // 탭별 WORD 데이터
    public ObservableCollection<WordViewModel> InputWords { get; } = [];
    public ObservableCollection<WordViewModel> OutputWords { get; } = [];
    public ObservableCollection<WordViewModel> ServoSystemWords { get; } = [];

    // 서보 파라미터 (DINT 값)
    private int _targetPos, _targetVel, _jogVel, _actPos, _actVel;
    private ushort _errCode, _actPosDeg;

    public int TargetPos { get => _targetPos; set { _targetPos = value; OnPropertyChanged(); } }
    public int TargetVel { get => _targetVel; set { _targetVel = value; OnPropertyChanged(); } }
    public int JogVel { get => _jogVel; set { _jogVel = value; OnPropertyChanged(); } }
    public int ActPos { get => _actPos; set { _actPos = value; OnPropertyChanged(); } }
    public int ActVel { get => _actVel; set { _actVel = value; OnPropertyChanged(); } }
    public ushort ErrCode { get => _errCode; set { _errCode = value; OnPropertyChanged(); } }
    public ushort ActPosDeg { get => _actPosDeg; set { _actPosDeg = value; OnPropertyChanged(); } }

    // 연결 상태
    private string _connectionStatus = "미연결";
    private bool _isConnected;
    private int _cycleMs;

    public string ConnectionStatus { get => _connectionStatus; set { _connectionStatus = value; OnPropertyChanged(); } }
    public bool IsConnected { get => _isConnected; set { _isConnected = value; OnPropertyChanged(); } }
    public int CycleMs { get => _cycleMs; set { _cycleMs = value; OnPropertyChanged(); } }

    // 디버그 로그 — 배치 업데이트로 UI 부하 최소화
    private readonly StringBuilder _logDisplay = new();
    private readonly StringBuilder _logPending = new();
    private readonly object _logLock = new();
    private const int MAX_LOG_CHARS = 50000;
    private string _logText = "";
    private bool _isLogEnabled = true;

    public string LogText { get => _logText; set { _logText = value; OnPropertyChanged(); } }
    public bool IsLogEnabled { get => _isLogEnabled; set { _isLogEnabled = value; OnPropertyChanged(); OnPropertyChanged(nameof(LogButtonText)); } }
    public string LogButtonText => IsLogEnabled ? "로그 중지" : "로그 시작";

    public IoMonitorViewModel()
    {
        // 통신 로그 콜백 연결
        _client.OnLog = AppendLog;

        // 입력 WORD 뷰모델 초기화
        foreach (var w in MemoryMapDefinition.InputMap)
            InputWords.Add(new WordViewModel(w));

        // 출력 WORD 뷰모델 초기화
        foreach (var w in MemoryMapDefinition.OutputMap)
            OutputWords.Add(new WordViewModel(w));

        // 서보/시스템 WORD 뷰모델 초기화
        foreach (var w in MemoryMapDefinition.ServoAndSystemMap)
            ServoSystemWords.Add(new WordViewModel(w));
    }

    /// <summary>
    /// PLC 연결 + 폴링 시작
    /// </summary>
    public async Task ConnectAndStartAsync()
    {
        ConnectionStatus = "연결 중...";
        var ok = await _client.ConnectAsync();
        if (!ok)
        {
            ConnectionStatus = $"연결 실패 ({_client.IpAddress}:{_client.Port})";
            IsConnected = false;
            return;
        }

        IsConnected = true;
        ConnectionStatus = $"연결됨 ({_client.IpAddress})";

        _cts = new CancellationTokenSource();
        _ = Task.Run(() => PollLoopAsync(_cts.Token));
    }

    /// <summary>
    /// 폴링 중지 + 연결 해제
    /// </summary>
    public void StopAndDisconnect()
    {
        _cts?.Cancel();
        _client.Disconnect();
        IsConnected = false;
        ConnectionStatus = "미연결";
    }

    /// <summary>
    /// 주기적으로 PLC MW 영역 읽기
    /// </summary>
    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            var sw = System.Diagnostics.Stopwatch.StartNew();
            try
            {
                // 입력 읽기: MW100~109 (10 WORD)
                var inputs = await _client.ReadWordsAsync("%MW100", 10);
                if (inputs != null)
                    UpdateWordViewModels(InputWords, inputs);

                // 출력 읽기: MW200~209 (10 WORD)
                var outputs = await _client.ReadWordsAsync("%MW200", 10);
                if (outputs != null)
                    UpdateWordViewModels(OutputWords, outputs);

                // 서보 명령 읽기: MW300~301 (2 WORD)
                var servoCmds = await _client.ReadWordsAsync("%MW300", 2);

                // 서보 파라미터 읽기: MW310~319 (10 WORD)
                var servoParams = await _client.ReadWordsAsync("%MW310", 10);

                // 서보 상태 읽기: MW400~401 (2 WORD)
                var servoStatus = await _client.ReadWordsAsync("%MW400", 2);

                // 서보 값 읽기: MW410~415 (6 WORD)
                var servoValues = await _client.ReadWordsAsync("%MW410", 6);

                // 시스템 읽기: MW500~501 (2 WORD)
                var system = await _client.ReadWordsAsync("%MW500", 2);

                // 서보/시스템 탭 업데이트
                var servoSysData = new ushort[6];
                if (servoCmds != null) { servoSysData[0] = servoCmds[0]; servoSysData[1] = servoCmds[1]; }
                if (servoStatus != null) { servoSysData[2] = servoStatus[0]; servoSysData[3] = servoStatus[1]; }
                if (system != null) { servoSysData[4] = system[0]; servoSysData[5] = system[1]; }
                UpdateWordViewModels(ServoSystemWords, servoSysData);

                // 서보 파라미터/값 (DINT) 업데이트
                if (servoParams is { Length: >= 6 })
                {
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        TargetPos = (int)(servoParams[0] | (servoParams[1] << 16));
                        TargetVel = (int)(servoParams[2] | (servoParams[3] << 16));
                        JogVel = (int)(servoParams[4] | (servoParams[5] << 16));
                    });
                }
                if (servoValues is { Length: >= 6 })
                {
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        ActPos = (int)(servoValues[0] | (servoValues[1] << 16));
                        ActVel = (int)(servoValues[2] | (servoValues[3] << 16));
                        ErrCode = servoValues[4];
                        ActPosDeg = servoValues[5];
                    });
                }

                sw.Stop();
                Application.Current?.Dispatcher.Invoke(() =>
                {
                    CycleMs = (int)sw.ElapsedMilliseconds;
                    ConnectionStatus = $"연결됨 ({_client.IpAddress}) — {CycleMs}ms";
                });
            }
            catch (Exception ex)
            {
                Application.Current?.Dispatcher.Invoke(() =>
                {
                    ConnectionStatus = $"통신 에러: {ex.Message}";
                });
            }

            // 사이클당 1회 로그 UI 반영 (배치)
            FlushLog();

            // 폴링 주기: 500ms (모니터링 용도, UI 부하 방지)
            await Task.Delay(500, ct).ConfigureAwait(false);
        }
    }

    private void UpdateWordViewModels(ObservableCollection<WordViewModel> vms, ushort[] data)
    {
        Application.Current?.Dispatcher.Invoke(() =>
        {
            for (int i = 0; i < Math.Min(vms.Count, data.Length); i++)
                vms[i].UpdateValue(data[i]);
        });
    }

    /// <summary>
    /// 로그 추가 — 버퍼에 축적, 사이클 끝에 FlushLog로 한번에 UI 업데이트
    /// </summary>
    private void AppendLog(string message)
    {
        if (!IsLogEnabled) return;
        lock (_logLock)
        {
            _logPending.AppendLine(message);
        }
    }

    /// <summary>
    /// 축적된 로그를 UI에 반영 (사이클당 1회)
    /// </summary>
    private void FlushLog()
    {
        string? pending;
        lock (_logLock)
        {
            if (_logPending.Length == 0) return;
            pending = _logPending.ToString();
            _logPending.Clear();
        }

        Application.Current?.Dispatcher.BeginInvoke(() =>
        {
            _logDisplay.Append(pending);

            // 최대 문자 수 초과 시 앞부분 제거
            if (_logDisplay.Length > MAX_LOG_CHARS)
            {
                var text = _logDisplay.ToString();
                var cutIndex = text.IndexOf('\n', text.Length / 2);
                if (cutIndex > 0)
                {
                    _logDisplay.Clear();
                    _logDisplay.Append(text, cutIndex + 1, text.Length - cutIndex - 1);
                }
            }

            LogText = _logDisplay.ToString();
        });
    }

    public void ToggleLog()
    {
        IsLogEnabled = !IsLogEnabled;
    }

    public void ClearLog()
    {
        lock (_logLock) { _logPending.Clear(); }
        _logDisplay.Clear();
        LogText = "";
    }

    public void Dispose()
    {
        StopAndDisconnect();
        _client.Dispose();
    }

    public event PropertyChangedEventHandler? PropertyChanged;
    protected void OnPropertyChanged([CallerMemberName] string? name = null)
        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
}

