    private static WordViewModel? FindParentWordViewModel(DependencyObject child)
    {
        var parent = VisualTreeHelper.GetParent(child);
        while (parent != null)
        {
            if (parent is FrameworkElement fe && fe.DataContext is WordViewModel wvm)
                return wvm;
            parent = VisualTreeHelper.GetParent(parent);
        }
        return null;
